import{_ as a,o as e,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Social Implications","description":"","frontmatter":{"title":"Social Implications","parent":"Theory (Paper 2)","nav_order":5,"has_children":true},"headers":[],"relativePath":"theory/social/index.md","filePath":"theory/social/index.md"}'),o={name:"theory/social/index.md"};function r(s,t,l,c,d,h){return e(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="social-implications" tabindex="-1">Social Implications <a class="header-anchor" href="#social-implications" aria-label="Permalink to &quot;Social Implications&quot;">​</a></h1><p>Social Implications examines the broader impact of Information Technology on individuals, communities and society. From intellectual property rights and cybercrime to the digital divide and environmental concerns, this topic asks students to think critically about the role technology plays in the world around them.</p><h2 id="what-s-in-this-section" tabindex="-1">What&#39;s in this section <a class="header-anchor" href="#what-s-in-this-section" aria-label="Permalink to &quot;What&#39;s in this section&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>What you&#39;ll learn</th></tr></thead><tbody><tr><td><a href="./copyright.html">Copyright &amp; Intellectual Property</a></td><td>Copyright law, software licensing, plagiarism, Creative Commons</td></tr><tr><td><a href="./cybercrime.html">Cybercrime</a></td><td>Types of cybercrime, hacking, phishing, identity theft, South African law (ECT Act)</td></tr><tr><td><a href="./online-safety.html">Online Safety</a></td><td>Protecting yourself online, safe browsing, strong passwords, two-factor authentication</td></tr><tr><td><a href="./privacy-ethics.html">Privacy &amp; Ethics</a></td><td>Right to privacy, POPIA, ethical use of data, surveillance, cookies and tracking</td></tr><tr><td><a href="./digital-divide.html">Digital Divide</a></td><td>Unequal access to technology in South Africa and globally, causes and solutions</td></tr><tr><td><a href="./environment-society.html">Environment &amp; Society</a></td><td>E-waste, energy consumption of data centres, green IT, impact on employment</td></tr></tbody></table><h2 id="caps-alignment" tabindex="-1">CAPS alignment <a class="header-anchor" href="#caps-alignment" aria-label="Permalink to &quot;CAPS alignment&quot;">​</a></h2><p>Social Implications is assessed in <strong>Paper 2</strong> across all grades and often forms part of scenario-based questions.</p><ul><li><strong>Grade 10</strong> — Copyright basics, safe internet use, types of cybercrime.</li><li><strong>Grade 11</strong> — Privacy, ethics, online safety measures, South African legislation.</li><li><strong>Grade 12</strong> — Digital divide, environmental impact, POPIA, advanced cybercrime and legislation.</li></ul>',7)])])}const g=a(o,[["render",r]]);export{p as __pageData,g as default};
